import{_ as l,G as t,c as r,o as d,j as e,J as n,a6 as s,a as i}from"./chunks/framework.D3uGTwuV.js";const O=JSON.parse('{"title":"Ollama 安装到 D 盘（方案一）：使用命令行指定路径","description":"","frontmatter":{},"headers":[],"relativePath":"技巧/程序安装强制更改路径（如果没有更改路径选项）.md","filePath":"技巧/程序安装强制更改路径（如果没有更改路径选项）.md","lastUpdated":1775109753000}'),c={name:"技巧/程序安装强制更改路径（如果没有更改路径选项）.md"};function _(m,a,p,h,g,f){const o=t("ArticleMetadata");return d(),r("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1775109753000"},[a[0]||(a[0]=e("h1",{id:"ollama-安装到-d-盘-方案一-使用命令行指定路径",tabindex:"-1"},[i("Ollama 安装到 D 盘（方案一）：使用命令行指定路径 "),e("a",{class:"header-anchor",href:"#ollama-安装到-d-盘-方案一-使用命令行指定路径","aria-label":"Permalink to “Ollama 安装到 D 盘（方案一）：使用命令行指定路径”"},"​")],-1)),n(o),a[1]||(a[1]=s('<h2 id="一、准备工作" tabindex="-1">一、准备工作 <a class="header-anchor" href="#一、准备工作" aria-label="Permalink to “一、准备工作”">​</a></h2><ol><li><strong>下载安装程序</strong>：访问 Ollama 官方网站（<a href="https://ollama.com/download" target="_blank" rel="noreferrer">https://ollama.com/download</a>），下载适用于 Windows 的安装程序 <code>OllamaSetup.exe</code>。</li></ol><h2 id="二、安装步骤" tabindex="-1">二、安装步骤 <a class="header-anchor" href="#二、安装步骤" aria-label="Permalink to “二、安装步骤”">​</a></h2><ol><li><strong>打开命令提示符</strong>：按 <code>Win + R</code> 键打开“运行”对话框，输入 <code>cmd</code>，然后按 <code>Enter</code> 键，打开命令提示符。</li></ol><p><strong>指定安装路径</strong>：在命令提示符中，运行以下命令来安装 Ollama 并指定安装路径为 D 盘的某个文件夹，例如 <code>D:\\Ollama</code>：</p><ol start="2"><li><code>OllamaSetup.exe /DIR=&quot;D:\\Ollama&quot;</code></li></ol><p><strong>提示</strong>：如果 <code>OllamaSetup.exe</code> 文件位于当前目录，可以使用相对路径运行安装程序，例如：</p><ol start="3"><li><code>.\\OllamaSetup.exe /DIR=&quot;D:\\Ollama&quot;</code></li></ol><p>这样可以更灵活地指定安装路径，尤其是在安装程序位于当前目录时。</p><h2 id="三、验证安装" tabindex="-1">三、验证安装 <a class="header-anchor" href="#三、验证安装" aria-label="Permalink to “三、验证安装”">​</a></h2><p><strong>验证安装是否成功</strong>：安装完成后，打开命令提示符或 PowerShell，输入以下命令验证安装是否成功：</p><ol><li><code>ollama --version</code></li></ol><p>如果显示 Ollama 的版本号，则说明安装成功。</p><h2 id="四、通用注意事项" tabindex="-1">四、通用注意事项 <a class="header-anchor" href="#四、通用注意事项" aria-label="Permalink to “四、通用注意事项”">​</a></h2><ul><li><strong>确保路径格式正确</strong>：在指定安装路径时，确保路径格式正确，避免使用中文字符或特殊符号。</li><li><strong>管理员权限</strong>：安装过程中可能需要管理员权限，因此建议以管理员身份运行命令提示符。</li><li><strong>修改路径时谨慎操作</strong>：在修改文件路径或命令时要谨慎，避免误删或误改重要文件。</li><li><strong>可适用于其他软件安装</strong>：此方法适用于许多 Windows 软件，可以通过命令行指定安装路径，安装到指定的磁盘或文件夹中。</li></ul>',15))])}const x=l(c,[["render",_]]);export{O as __pageData,x as default};
